#!/usr/bin/env node

/**
 * Diff Coverage Calculator -- Node/JS
 *
 * Calculates coverage for only the lines changed in a PR (diff coverage),
 * matching Fury Code Health methodology:
 * - Only changed/added lines count toward coverage
 * - Partial branch coverage = NOT covered
 * - Threshold: 75%
 *
 * Generated by claudify -- do not edit manually.
 */

const { spawnSync } = require('child_process');
const fs = require('fs');
const path = require('path');

const THRESHOLD = 75;
const BASE_BRANCH = 'origin/develop';
// Note: Only assets/js/ and packages/ contain runtime JS source code.
// src/ is PHP-only. tests/ and e2e/ are excluded (test code, not source).
const SOURCE_DIRS = ['assets/js/', 'packages/'];
const COVERAGE_JSON_PATH = path.resolve('coverage/coverage-final.json');

// --- Helpers ---------------------------------------------------------------

function run(cmd, args, options = {}) {
  const maxBuffer = options.maxBuffer || 10 * 1024 * 1024;
  const timeout = options.timeout || undefined;
  const result = spawnSync(cmd, args, { encoding: 'utf-8', maxBuffer, timeout });
  return { stdout: result.stdout || '', stderr: result.stderr || '', status: result.status };
}

function isSafePath(filePath) {
  if (filePath.startsWith('-')) return false;
  if (filePath.includes('..')) return false;
  if (path.isAbsolute(filePath)) return false;
  return true;
}

function isSourceFile(filePath) {
  if (!filePath.match(/\.(js|jsx|ts|tsx)$/)) return false;
  // Exclude test/spec files by filename suffix
  if (filePath.match(/\.(test|spec)\.(js|jsx|ts|tsx)$/)) return false;
  // Exclude test/mock directories (match as path segments, not substrings)
  if (filePath.match(/(^|\/)(__tests__|__mocks__|fixtures?)(\/|\.)/i)) return false;
  return SOURCE_DIRS.some((dir) => filePath.startsWith(dir));
}

// --- Parse git diff to extract changed line numbers per file ----------------

function getChangedLines() {
  const { stdout, stderr, status } = run(
    'git',
    ['diff', `${BASE_BRANCH}...HEAD`, '-U0', '--diff-filter=ACMR', '--no-color'],
    { maxBuffer: 50 * 1024 * 1024 },
  );

  if (status !== 0) {
    console.error(`git diff failed (exit code ${status}):`);
    console.error(stderr);
    console.error(`\nMake sure '${BASE_BRANCH}' is fetched. Run: git fetch origin develop`);
    process.exit(1);
  }

  const changedLines = new Map(); // filePath -> Set<lineNumber>
  let currentFile = null;

  for (const line of stdout.split('\n')) {
    // Match diff header: +++ b/path/to/file.ts
    const fileMatch = line.match(/^\+\+\+ b\/(.+)$/);
    if (fileMatch) {
      currentFile = fileMatch[1];
      continue;
    }

    // Match hunk header: @@ -old,count +new,count @@
    const hunkMatch = line.match(/^@@ -\d+(?:,\d+)? \+(\d+)(?:,(\d+))? @@/);
    if (hunkMatch && currentFile) {
      const start = parseInt(hunkMatch[1], 10);
      const count = hunkMatch[2] !== undefined ? parseInt(hunkMatch[2], 10) : 1;

      if (count === 0) continue; // Deletion-only hunk

      if (!changedLines.has(currentFile)) {
        changedLines.set(currentFile, new Set());
      }
      const lineSet = changedLines.get(currentFile);
      for (let i = start; i < start + count; i++) {
        lineSet.add(i);
      }
    }
  }

  return changedLines;
}

// --- Analyze Istanbul coverage data for changed lines -----------------------

function analyzeCoverage(coverageData, changedLines) {
  const results = [];
  let totalCoverable = 0;
  let totalCovered = 0;

  for (const [filePath, lines] of changedLines.entries()) {
    // Find the matching coverage entry -- Istanbul uses absolute paths
    const absolutePath = path.resolve(filePath);
    const fileCoverage = coverageData[absolutePath];

    if (!fileCoverage) {
      // File has no coverage data -- no tests import it
      // Count all changed lines as coverable to prevent inflated percentages
      const lineCount = lines.size;
      results.push({
        file: filePath,
        coverable: lineCount,
        covered: 0,
        percentage: 0,
        uncoveredLines: [...lines].sort((a, b) => a - b),
        warning: 'No coverage data -- no tests import this file',
      });
      totalCoverable += lineCount;
      continue;
    }

    // Build a map of line -> coverage status
    // A line is "coverable" if it appears in the statement map
    // A line is "covered" if its statement count > 0 AND all branches on it are fully covered
    const { statementMap, s: statementCounts, branchMap, b: branchCounts } = fileCoverage;

    // Map lines to their statement coverage
    const lineStatements = new Map(); // line -> { coverable: bool, covered: bool }

    // Process statements: mark lines as coverable and check counts
    for (const [stmtId, loc] of Object.entries(statementMap)) {
      const startLine = loc.start.line;
      const endLine = loc.end.line;

      for (let line = startLine; line <= endLine; line++) {
        if (!lines.has(line)) continue; // Only care about changed lines

        if (!lineStatements.has(line)) {
          lineStatements.set(line, { coverable: true, covered: true });
        }

        // If any statement on this line has 0 executions, line is not covered
        if (statementCounts[stmtId] === 0) {
          lineStatements.get(line).covered = false;
        }
      }
    }

    // Process branches: partial branch coverage = NOT covered
    for (const [branchId, branchInfo] of Object.entries(branchMap)) {
      const branchExecCounts = branchCounts[branchId] || [];
      const hasUncoveredArm = branchExecCounts.some((count) => count === 0);
      if (!hasUncoveredArm) continue;

      // Check the main branch declaration line
      const mainLine = branchInfo.loc?.start?.line;
      if (mainLine && lines.has(mainLine)) {
        if (!lineStatements.has(mainLine)) {
          lineStatements.set(mainLine, { coverable: true, covered: false });
        } else {
          lineStatements.get(mainLine).covered = false;
        }
      }

      // Also check each individual branch arm location
      const locations = branchInfo.locations || [];
      for (const armLoc of locations) {
        const armLine = armLoc?.start?.line;
        if (armLine && lines.has(armLine)) {
          if (!lineStatements.has(armLine)) {
            lineStatements.set(armLine, { coverable: true, covered: false });
          } else {
            lineStatements.get(armLine).covered = false;
          }
        }
      }
    }

    // Count coverable and covered changed lines
    let fileCoverable = 0;
    let fileCovered = 0;
    const uncoveredLines = [];

    for (const line of lines) {
      const info = lineStatements.get(line);
      if (info && info.coverable) {
        fileCoverable++;
        if (info.covered) {
          fileCovered++;
        } else {
          uncoveredLines.push(line);
        }
      }
      // Lines not in statement map are non-coverable (comments, whitespace, etc.)
    }

    const percentage = fileCoverable > 0 ? (fileCovered / fileCoverable) * 100 : 100;

    results.push({
      file: filePath,
      coverable: fileCoverable,
      covered: fileCovered,
      percentage,
      uncoveredLines: uncoveredLines.sort((a, b) => a - b),
    });

    totalCoverable += fileCoverable;
    totalCovered += fileCovered;
  }

  return { results, totalCoverable, totalCovered };
}

// --- Main ------------------------------------------------------------------

function main() {
  console.log('Running diff coverage check (Fury Code Health methodology)...');
  console.log('========================================\n');

  // 1. Get changed lines from git diff
  const allChangedLines = getChangedLines();

  if (allChangedLines.size === 0) {
    console.log('No files changed compared to', BASE_BRANCH);
    console.log('Diff coverage check passed!');
    process.exit(0);
  }

  // 2. Filter to testable source files
  const sourceChangedLines = new Map();
  for (const [filePath, lines] of allChangedLines.entries()) {
    if (isSafePath(filePath) && isSourceFile(filePath)) {
      sourceChangedLines.set(filePath, lines);
    }
  }

  // 3. List all changed files with source/non-source icons
  console.log('Changed files in this PR:');
  for (const filePath of allChangedLines.keys()) {
    const isSource = sourceChangedLines.has(filePath);
    console.log(`  ${isSource ? '[src]' : '[---]'} ${filePath}`);
  }
  console.log('');

  if (sourceChangedLines.size === 0) {
    console.log('No testable source files changed.');
    console.log('   Only test files, config files, or non-source files were modified.');
    console.log('Diff coverage check passed!');
    process.exit(0);
  }

  // 4. Build collectCoverageFrom patterns for changed source files
  const collectCoverageFrom = [...sourceChangedLines.keys()].map((f) => `<rootDir>/${f}`);

  console.log(`Analyzing diff coverage for ${sourceChangedLines.size} source file(s)...\n`);

  // 5. Clean stale coverage data to avoid reading outdated results
  if (fs.existsSync(COVERAGE_JSON_PATH)) {
    fs.unlinkSync(COVERAGE_JSON_PATH);
  }

  // 6. Run Jest with JSON coverage reporter using a temporary config
  //    (CLI --collectCoverageFrom doesn't work reliably with multi-project configs)
  const configCandidates = ['jest.config.ts', 'jest.config.js', 'jest.config.mjs', 'jest.config.cjs'];
  const foundConfig = configCandidates.find((f) => fs.existsSync(path.resolve(f)));

  // Fallback: check if Jest is configured in package.json
  let jestInPackageJson = false;
  if (!foundConfig) {
    try {
      const pkg = JSON.parse(fs.readFileSync(path.resolve('package.json'), 'utf-8'));
      jestInPackageJson = !!pkg.jest;
    } catch (_) {
      // no package.json or invalid JSON
    }
  }

  if (!foundConfig && !jestInPackageJson) {
    console.error('No Jest configuration found (checked jest.config.{ts,js,mjs,cjs} and package.json).');
    console.error('   Ensure Jest is configured before running diff coverage.');
    process.exit(1);
  }

  const baseConfigPath = foundConfig ? path.resolve(foundConfig) : null;
  const isESM = foundConfig && foundConfig.endsWith('.mjs');
  const tmpExt = isESM ? '.mjs' : '.js';
  const tmpConfigPath = path.resolve(`coverage/.diff-coverage-jest.config${tmpExt}`);

  // Ensure coverage directory exists
  const coverageDir = path.dirname(tmpConfigPath);
  if (!fs.existsSync(coverageDir)) {
    fs.mkdirSync(coverageDir, { recursive: true });
  }

  const projectRoot = JSON.stringify(path.resolve('.'));
  let tmpConfigContent;

  if (isESM) {
    // ESM config: use dynamic import()
    tmpConfigContent = [
      `const { default: baseConfig } = await import(${JSON.stringify(baseConfigPath)});`,
      `const collectCoverageFrom = ${JSON.stringify(collectCoverageFrom)};`,
      `export default {`,
      `  ...baseConfig,`,
      `  rootDir: ${projectRoot},`,
      `  collectCoverageFrom,`,
      `  coverageReporters: ['json'],`,
      `  ...(baseConfig.projects ? {`,
      `    projects: baseConfig.projects.map(p => ({`,
      `      ...p,`,
      `      rootDir: ${projectRoot},`,
      `      collectCoverageFrom,`,
      `    })),`,
      `  } : {}),`,
      `};`,
    ].join('\n');
  } else if (baseConfigPath) {
    // CJS config: use require()
    tmpConfigContent = [
      `const baseConfig = require(${JSON.stringify(baseConfigPath)});`,
      `const collectCoverageFrom = ${JSON.stringify(collectCoverageFrom)};`,
      `module.exports = {`,
      `  ...baseConfig,`,
      `  rootDir: ${projectRoot},`,
      `  collectCoverageFrom,`,
      `  coverageReporters: ['json'],`,
      `  ...(baseConfig.projects ? {`,
      `    projects: baseConfig.projects.map(p => ({`,
      `      ...p,`,
      `      rootDir: ${projectRoot},`,
      `      collectCoverageFrom,`,
      `    })),`,
      `  } : {}),`,
      `};`,
    ].join('\n');
  } else {
    // Jest configured in package.json -- generate minimal config
    tmpConfigContent = [
      `const collectCoverageFrom = ${JSON.stringify(collectCoverageFrom)};`,
      `module.exports = {`,
      `  rootDir: ${projectRoot},`,
      `  collectCoverageFrom,`,
      `  coverageReporters: ['json'],`,
      `};`,
    ].join('\n');
  }
  fs.writeFileSync(tmpConfigPath, tmpConfigContent);

  // Clean up temp config on any exit (SIGTERM, Ctrl+C, crash)
  const cleanupTmpConfig = () => {
    try {
      fs.unlinkSync(tmpConfigPath);
    } catch (_) {
      // Ignore cleanup errors
    }
  };
  process.on('exit', cleanupTmpConfig);

  const changedFilePaths = [...sourceChangedLines.keys()];
  const jestResult = run(
    'npx',
    [
      'jest',
      '--coverage',
      `--config=${tmpConfigPath}`,
      '--passWithNoTests',
      '--silent',
      '--findRelatedTests',
      ...changedFilePaths,
    ],
    { timeout: 5 * 60 * 1000 },
  );

  if (jestResult.status === null) {
    console.error('Jest timed out after 5 minutes.');
    console.error('   Try running tests manually to identify hanging tests.');
    process.exit(1);
  }

  if (jestResult.status !== 0) {
    if (jestResult.status !== 1) {
      console.error('Jest failed to run (exit code', jestResult.status, '):', jestResult.stderr);
      process.exit(1);
    } else {
      console.warn('Some tests failed. Coverage data may be incomplete.');
      console.warn('   Fix failing tests for accurate diff coverage results.');
    }
  }

  // 7. Read Istanbul coverage JSON
  if (!fs.existsSync(COVERAGE_JSON_PATH)) {
    console.error('Coverage JSON not found at', COVERAGE_JSON_PATH);
    console.error('   Jest may have failed to generate coverage data.');
    process.exit(1);
  }

  let coverageData;
  try {
    coverageData = JSON.parse(fs.readFileSync(COVERAGE_JSON_PATH, 'utf-8'));
  } catch (err) {
    console.error('Failed to parse coverage JSON at', COVERAGE_JSON_PATH);
    console.error('   File may be corrupted. Try deleting coverage/ and re-running.');
    console.error('   Error:', err.message);
    process.exit(1);
  }

  // 8. Analyze coverage for changed lines
  const { results, totalCoverable, totalCovered } = analyzeCoverage(
    coverageData,
    sourceChangedLines,
  );

  // 9. Report results
  console.log('Diff Coverage Results (changed lines only):');
  console.log('-------------------------------------------');

  for (const r of results) {
    if (r.warning) {
      console.log(`  [WARN] ${r.file}: ${r.warning}`);
      continue;
    }
    const icon = r.percentage >= THRESHOLD ? '[PASS]' : '[FAIL]';
    const pct = r.percentage.toFixed(1);
    console.log(`  ${icon} ${r.file}: ${pct}% (${r.covered}/${r.coverable} lines)`);
    if (r.uncoveredLines.length > 0 && r.uncoveredLines.length <= 20) {
      console.log(`     Uncovered lines: ${r.uncoveredLines.join(', ')}`);
    } else if (r.uncoveredLines.length > 20) {
      const shown = r.uncoveredLines.slice(0, 20).join(', ');
      console.log(`     Uncovered lines: ${shown} ... and ${r.uncoveredLines.length - 20} more`);
    }
  }

  console.log('-------------------------------------------');

  const overallPercentage = totalCoverable > 0 ? (totalCovered / totalCoverable) * 100 : 100;

  console.log(
    `\nOverall diff coverage: ${overallPercentage.toFixed(1)}% (${totalCovered}/${totalCoverable} changed lines covered)`,
  );

  // Warn about files with no coverage data
  const uncoveredFiles = results.filter((r) => r.warning);
  if (uncoveredFiles.length > 0) {
    console.log(
      `\n${uncoveredFiles.length} file(s) have no test coverage at all (counted as 0% covered)`,
    );
  }

  if (totalCoverable === 0) {
    console.log('   No coverable lines in changed files (all comments/whitespace/types).');
    console.log('Diff coverage check passed!');
    process.exit(0);
  }

  if (overallPercentage >= THRESHOLD) {
    console.log(`Diff coverage meets requirement (>=${THRESHOLD}%)`);
    process.exit(0);
  } else {
    console.log(`Diff coverage too low: ${overallPercentage.toFixed(1)}% (need >=${THRESHOLD}%)`);
    console.log('');
    console.log('To fix this:');
    console.log('1. Add tests that exercise the specific lines you changed');
    console.log('2. Check the uncovered lines listed above');
    console.log('3. Ensure branch conditions (if/else) are fully tested');
    console.log('4. Note: partial branch coverage counts as NOT covered');
    process.exit(1);
  }
}

main();
